	var afterTime *time.Time
	var beforeTime *time.Time
	if startedAfter != nil && *startedAfter != "" {
		if parsed, err := time.Parse(time.RFC3339, *startedAfter); err == nil {
			afterTime = &parsed
		}
	}
	if startedBefore != nil && *startedBefore != "" {
