// TestRunLMStudioDispatchesThroughEmbeddedAgent is the regression for
// ddx-501e87ef. An lmstudio candidate has Binary="" and
// Surface="embedded-openai" because lmstudio is an HTTP-only provider —
// there's no CLI binary to exec. The dispatch must recognize this and
// route through RunAgent (the embedded OpenAI-compatible runtime),
// NOT fall through to the exec-a-binary path which would call
// r.Executor.ExecuteInDir(ctx, "", args, ...) and produce a zero-duration
// "exec: no command" error.
//
// Symptom in production (host 'eitri', 2026-04-17): routing picked
// lmstudio correctly; exec dispatch returned status=execution_failed,
// detail="exec: no command", duration_ms=0, exit_code=-1. Cheap tier
// was burning <1s per bead and escalating straight to smart tier.
func TestRunLMStudioDispatchesThroughEmbeddedAgent(t *testing.T) {
	mock := &mockExecutor{output: "should not be called"}
	r := newTestRunner(mock)

	// Invoke with explicit --harness lmstudio. Without AgentProvider set,
	// RunAgent will fail to resolve a provider — that's fine; the check
	// is that the exec path is NEVER reached.
	_, _ = r.Run(RunOptions{Harness: "lmstudio", Prompt: "hello"})

	// The mockExecutor's ExecuteInDir records the last binary it was
	// asked to run. If the dispatch fix is working, it was never called
	// and lastBinary stays empty.
	if mock.lastBinary != "" {
		t.Errorf("lmstudio dispatch leaked to exec path: got lastBinary=%q (want empty — dispatch should route through RunAgent)", mock.lastBinary)
	}
}

// Same check for openrouter — same root cause, same fix.
func TestRunOpenRouterDispatchesThroughEmbeddedAgent(t *testing.T) {
	mock := &mockExecutor{output: "should not be called"}
	r := newTestRunner(mock)

	_, _ = r.Run(RunOptions{Harness: "openrouter", Prompt: "hello"})

	if mock.lastBinary != "" {
		t.Errorf("openrouter dispatch leaked to exec path: got lastBinary=%q (want empty)", mock.lastBinary)
	}
}

package agent

// RunAgent executes a prompt using the agentlib.DdxAgent service path.
// This runs in-process — no subprocess, no binary lookup.
//
// Phase 5h migration (ddx-4e3e149f): converted from a (*Runner) method
// to a free function taking r as an explicit parameter, matching the
// dispatch style used everywhere else in this package after the
// Runner-method-to-free-function refactor landed.
//
// To disable the new path as an emergency escape hatch, set the env var
// DDX_USE_NEW_AGENT_PATH=0 (or "false"). Default is the new service path.
func RunAgent(r *Runner, opts RunOptions) (*Result, error) {
	if useNewAgentPath() {
		return runAgentViaService(r, opts)
	}
	// Emergency fallback: reached only when DDX_USE_NEW_AGENT_PATH=0.
	// The legacy in-package agentlib.Run loop has been removed (ddx-d224671d).
	// If this branch is needed, re-enable by reverting that bead.
	return runAgentViaService(r, opts)
}
// useNewAgentPath reports whether RunAgent should dispatch to the new
// agentlib.DdxAgent.Execute path. Default is on. Set the env var
// DDX_USE_NEW_AGENT_PATH=0 (or "false") to disable as an emergency escape
// hatch.
func useNewAgentPath() bool {
	switch os.Getenv("DDX_USE_NEW_AGENT_PATH") {
	case "0", "false", "FALSE", "False":
		return false
	default:
		return true
	}
}

// runAgentViaService is the new RunAgent dispatch path that drives the
// agent through agentlib.DdxAgent.Execute and drains the resulting event
// channel into a DDx Result. Old in-package code paths (RunAgent legacy
// loop, embeddedCompactionConfig, buildAgentProvider, findTool,
// wrapProviderWithDeadlines, stall + compaction-stuck circuit breakers)
// stay in place; this function does NOT call them.
//
// Stall detection: we delegate to the agent's StallPolicy. The agent
// emits a stall event then a final event with Status="stalled".
func runAgentViaService(r *Runner, opts RunOptions) (*Result, error) {
	promptText, err := r.resolvePrompt(opts)
	if err != nil {
		return nil, err
	}

	model := r.resolveModel(opts, "agent")
	timeout := r.resolveTimeout(opts)
	wallClock := r.resolveWallClock(opts)

	wd := opts.WorkDir
	if wd == "" {
		wd, _ = os.Getwd()
	}

	// Construct the service. Reuses NewServiceFromWorkDir so provider/model
	// routing data lands on the agent the same way every other DDx command
	// constructs it (see serviceconfig.go).
	svc, err := NewServiceFromWorkDir(wd)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}

	// Resolve where to write the per-request session log.
	logDir := opts.SessionLogDir
	if logDir == "" {
		logDir = r.Config.SessionLogDir
	}
	if logDir == "" {
		logDir = DefaultLogDir
	}

	// Build the public ExecuteRequest per CONTRACT-003.
	req := agentlib.ServiceExecuteRequest{
		Prompt:          promptText,
		Model:           model,
		Provider:        opts.Provider,
		Harness:         "agent",
		ModelRef:        opts.ModelRef,
		Reasoning:       agentlib.Reasoning(opts.Effort),
		Permissions:     opts.Permissions,
		WorkDir:         wd,
		Timeout:         wallClock,
		IdleTimeout:     timeout,
